#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

// =============================================================================
// LINKED LIST NODE STRUCTURE
// =============================================================================

struct Node {
 int data;
 struct Node* next;
};

// Type alias for convenience
typedef struct Node Node;

// =============================================================================
// LINKED LIST OPERATIONS
// =============================================================================

// Create a new node (O(1))
Node* createNode(int data) {
 Node* newNode = (Node*)malloc(sizeof(Node));
 if (newNode == NULL) {
 printf("Memory allocation failed!\n");
 exit(1);
 }
 newNode->data = data;
 newNode->next = NULL;
 return newNode;
}

// Insert at the beginning (O(1))
Node* insertAtFront(Node* head, int data) {
 Node* newNode = createNode(data);
 newNode->next = head;
 return newNode;
}

// Insert at the end (O(n))
Node* insertAtEnd(Node* head, int data) {
 Node* newNode = createNode(data);

 if (head == NULL) {
 return newNode;
 }

 Node* current = head;
 while (current->next != NULL) {
 current = current->next;
 }
 current->next = newNode;
 return head;
}

// Insert at a specific position (O(n))
Node* insertAtPosition(Node* head, int data, int position) {
 if (position == 0) {
 return insertAtFront(head, data);
 }

 Node* newNode = createNode(data);
 Node* current = head;

 // Traverse to position-1
 for (int i = 0; i < position - 1 && current != NULL; i++) {
 current = current->next;
 }

 if (current == NULL) {
 printf("Position out of bounds\n");
 free(newNode);
 return head;
 }

 newNode->next = current->next;
 current->next = newNode;
 return head;
}

// Delete from front (O(1))
Node* deleteFromFront(Node* head) {
 if (head == NULL) {
 printf("List is empty\n");
 return NULL;
 }
 Node* temp = head;
 head = head->next;
 free(temp);
 return head;
}

// Search for an element (O(n))
int search(Node* head, int key) {
 Node* current = head;
 int position = 0;

 while (current != NULL) {
 if (current->data == key) {
 return position;
 }
 current = current->next;
 position++;
 }
 return -1; // Not found
}

// Display the linked list
void display(Node* head) {
 if (head == NULL) {
 printf("List is empty\n");
 return;
 }

 printf("Linked List: ");
 Node* current = head;
 while (current != NULL) {
 printf("%d -> ", current->data);
 current = current->next;
 }
 printf("NULL\n");
}

// Free all nodes
void freeList(Node* head) {
 Node* current = head;
 while (current != NULL) {
 Node* temp = current;
 current = current->next;
 free(temp);
 }
}

// =============================================================================
// MAIN DEMONSTRATION
// =============================================================================

int main() {
 Node* head = NULL;

 printf("========================================\n");
 printf("LINKED LIST DEMONSTRATION\n");
 printf("========================================\n\n");

 // Insert elements
 printf("--- Insertion Operations ---\n");

 // Insert at end
 head = insertAtEnd(head, 10);
 head = insertAtEnd(head, 20);
 head = insertAtEnd(head, 30);
 printf("After inserting 10, 20, 30 at end: ");
 display(head);

 // Insert at front
 head = insertAtFront(head, 5);
 printf("After inserting 5 at front: ");
 display(head);

 // Insert at position 2
 head = insertAtPosition(head, 25, 2);
 printf("After inserting 25 at position 2: ");
 display(head);

 // Search operation
 printf("\n--- Search Operations ---\n");
 int pos = search(head, 20);
 if (pos != -1) {
 printf("Element 20 found at position %d\n", pos);
 } else {
 printf("Element 20 not found\n");
 }

 // Delete operation
 printf("\n--- Deletion Operations ---\n");
 head = deleteFromFront(head);
 printf("After deleting from front: ");
 display(head);

 // Summary of Time Complexities
 printf("\n========================================\n");
 printf("TIME COMPLEXITY SUMMARY:\n");
 printf("========================================\n");
 printf("Insert at front: O(1)\n");
 printf("Insert at end: O(n)\n");
 printf("Insert at position: O(n)\n");
 printf("Delete from front: O(1)\n");
 printf("Search: O(n)\n");
 printf("Access by position: O(n)\n");
 printf("========================================\n");

 // Clean up
 freeList(head);

 return 0;
}

// =============================================================================
// BINARY SEARCH TREE (BST) - A Non-Linear Hierarchical Data Structure
// =============================================================================

class Node {
 int key;
 Node left, right;

 public Node(int item) {
 key = item;
 left = right = null;
 }
}

class BinarySearchTree {
 Node root;

 // Constructor
 BinarySearchTree() {
 root = null;
 }

 // =========================================================================
 // INSERT OPERATION - O(log n) average, O(n) worst case
 // =========================================================================

 void insert(int key) {
 root = insertRec(root, key);
 }

 Node insertRec(Node root, int key) {
 // Base case: empty tree or reached leaf
 if (root == null) {
 root = new Node(key);
 return root;
 }

 // Otherwise, recur down the tree
 if (key < root.key) {
 root.left = insertRec(root.left, key);
 } else if (key > root.key) {
 root.right = insertRec(root.right, key);
 }

 return root;
 }

 // =========================================================================
 // SEARCH OPERATION - O(log n) average, O(n) worst case
 // =========================================================================

 Node search(int key) {
 return searchRec(root, key);
 }

 Node searchRec(Node root, int key) {
 // Base case: root is null or key is at root
 if (root == null || root.key == key) {
 return root;
 }

 // Key is greater than root's key
 if (key > root.key) {
 return searchRec(root.right, key);
 }

 // Key is smaller than root's key
 return searchRec(root.left, key);
 }

 // =========================================================================
 // INORDER TRAVERSAL - Left, Root, Right (gives sorted order)
 // =========================================================================

 void inorder() {
 System.out.print("Inorder (Sorted): ");
 inorderRec(root);
 System.out.println();
 }

 void inorderRec(Node root) {
 if (root != null) {
 inorderRec(root.left);
 System.out.print(root.key + " ");
 inorderRec(root.right);
 }
 }

 // =========================================================================
 // PREORDER TRAVERSAL - Root, Left, Right
 // =========================================================================

 void preorder() {
 System.out.print("Preorder: ");
 preorderRec(root);
 System.out.println();
 }

 void preorderRec(Node root) {
 if (root != null) {
 System.out.print(root.key + " ");
 preorderRec(root.left);
 preorderRec(root.right);
 }
 }

 // =========================================================================
 // POSTORDER TRAVERSAL - Left, Right, Root
 // =========================================================================

 void postorder() {
 System.out.print("Postorder: ");
 postorderRec(root);
 System.out.println();
 }

 void postorderRec(Node root) {
 if (root != null) {
 postorderRec(root.left);
 postorderRec(root.right);
 System.out.print(root.key + " ");
 }
 }

 // =========================================================================
 // DELETE OPERATION
 // =========================================================================

 void delete(int key) {
 root = deleteRec(root, key);
 }

 Node deleteRec(Node root, int key) {
 // Base case
 if (root == null) {
 return root;
 }

 // Recur down the tree
 if (key < root.key) {
 root.left = deleteRec(root.left, key);
 } else if (key > root.key) {
 root.right = deleteRec(root.right, key);
 } else {
 // Node with only one child or no child
 if (root.left == null) {
 return root.right;
 } else if (root.right == null) {
 return root.left;
 }

 // Node with two children: get inorder successor (smallest in right subtree)
 Node minLargerNode = minValueNode(root.right);
 root.key = minLargerNode.key;
 root.right = deleteRec(root.right, minLargerNode.key);
 }
 return root;
 }

 Node minValueNode(Node node) {
 Node current = node;
 while (current.left != null) {
 current = current.left;
 }
 return current;
 }
}

// =============================================================================
// MAIN CLASS - DEMONSTRATION
// =============================================================================

public class BSTDemo {
 public static void main(String[] args) {
 System.out.println("========================================");
 System.out.println("BINARY SEARCH TREE DEMONSTRATION");
 System.out.println("========================================\n");

 BinarySearchTree bst = new BinarySearchTree();

 // Insert elements
 System.out.println("--- Inserting Elements ---");
 int[] elements = {50, 30, 70, 20, 40, 60, 80};

 for (int elem : elements) {
 bst.insert(elem);
 System.out.println("Inserted: " + elem);
 }

 // Tree Structure:
 // 50
 // / \
 // 30 70
 // / \ / \
 // 20 40 60 80

 System.out.println("\n--- Tree Traversals ---");
 bst.inorder(); // 20 30 40 50 60 70 80 (sorted)
 bst.preorder(); // 50 30 20 40 70 60 80
 bst.postorder(); // 20 40 30 60 80 70 50

 // Search operation
 System.out.println("\n--- Search Operation ---");
 int searchKey = 40;
 Node result = bst.search(searchKey);
 if (result != null) {
 System.out.println("Element " + searchKey + " found in BST");
 } else {
 System.out.println("Element " + searchKey + " not found");
 }

 // Delete operation
 System.out.println("\n--- Delete Operation ---");
 System.out.println("Deleting 20 (node with no children)");
 bst.delete(20);
 bst.inorder();

 System.out.println("Deleting 30 (node with one child)");
 bst.delete(30);
 bst.inorder();

 System.out.println("Deleting 50 (root node with two children)");
 bst.delete(50);
 bst.inorder();

 // Summary
 System.out.println("\n========================================");
 System.out.println("BST COMPLEXITY SUMMARY:");
 System.out.println("========================================");
 System.out.println("Search: O(log n) avg, O(n) worst");
 System.out.println("Insert: O(log n) avg, O(n) worst");
 System.out.println("Delete: O(log n) avg, O(n) worst");
 System.out.println("Traversal: O(n)");
 System.out.println("========================================");
 System.out.println("\nNote: O(n) worst case occurs when tree");
 System.out.println("becomes skewed (like a linked list)");
 System.out.println("========================================");
 }
}
